pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
    // Walk down the tree, incrementing counts
    let mut current = self.root_node.clone();
    let mut parent: Option<Rc<RefCell<BOSNode>>> = None;
    let mut went_left = false;

    while let Some(ref node_rc) = current {
        parent = Some(node_rc.clone());
        let cmp = (self.cmp_function)(&key, &node_rc.borrow().key);
        if cmp < 0 {
            node_rc.borrow_mut().left_child_count += 1;
            went_left = true;
            current = node_rc.borrow().left_child_node.clone();
        } else {
            node_rc.borrow_mut().right_child_count += 1;
            went_left = false;
            current = node_rc.borrow().right_child_node.clone();
        }
    }

    // Create new node
    let new_node = Rc::new(RefCell::new(BOSNode {
        left_child_count: 0,
        right_child_count: 0,
        depth: 0,
        left_child_node: None,
        right_child_node: None,
        parent_node: parent.as_ref().map(|p| Rc::downgrade(p)),
        key,
        data,
        weak_ref_count: 1,
        weak_ref_node_valid: 1,
    }));

    // Insert into tree
    match parent {
        None => {
            self.root_node = Some(new_node.clone());
            return new_node;
        }
        Some(ref parent_rc) => {
            if went_left {
                parent_rc.borrow_mut().left_child_node = Some(new_node.clone());
            } else {
                parent_rc.borrow_mut().right_child_node = Some(new_node.clone());
            }
        }
    }

    // Check if depth changed (only if this is first child)
    let parent_rc = parent.as_ref().unwrap();
    let has_left = parent_rc.borrow().left_child_node.is_some();
    let has_right = parent_rc.borrow().right_child_node.is_some();

    if has_left ^ has_right {
        // This was the first child, depth increased
        parent_rc.borrow_mut().depth += 1;

        let mut current_parent = parent.clone();
        while let Some(ref cur_rc) = current_parent {
            let parent_of_cur = cur_rc.borrow().parent_node.as_ref().and_then(|w| w.upgrade());

            if let Some(ref parent_of_cur_rc) = parent_of_cur {
                let mut p = parent_of_cur_rc.borrow_mut();
                let new_left_depth = p.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                let new_right_depth = p.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                let max_depth = imax(new_left_depth, new_right_depth);

