            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        self.root_node.as_ref().map_or(0, |n| {
            let n = n.borrow();
            n.left_child_count + n.right_child_count + 1
        })
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let cmp_fn = self.cmp_function;
        let mut path: Vec<(Rc<RefCell<BOSNode>>, bool)> = Vec::new();

        let mut current = self.root_node.clone();
        while let Some(ref node_rc) = current {
            let cmp = cmp_fn(&key, &node_rc.borrow().key);
            if cmp < 0 {
                node_rc.borrow_mut().left_child_count += 1;
                let next = node_rc.borrow().left_child_node.clone();
                path.push((node_rc.clone(), true));
                current = next;
            } else {
                node_rc.borrow_mut().right_child_count += 1;
                let next = node_rc.borrow().right_child_node.clone();
                path.push((node_rc.clone(), false));
                current = next;
            }
        }

        let parent_weak = path.last().map(|(n, _)| Rc::downgrade(n));
        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: parent_weak,
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        if let Some((parent, went_left)) = path.last() {
            if *went_left {
                parent.borrow_mut().left_child_node = Some(new_node.clone());
            } else {
                parent.borrow_mut().right_child_node = Some(new_node.clone());
            }
        } else {
            self.root_node = Some(new_node.clone());
            return new_node;
        }

        // Depth only changes when parent goes from 0 to 1 children
        let should_bubble = {
            let p = path.last().unwrap().0.borrow();
            p.left_child_node.is_some() ^ p.right_child_node.is_some()
        };

        if should_bubble {
            let parent_idx = path.len() - 1;
            path[parent_idx].0.borrow_mut().depth += 1;

            for i in (0..parent_idx).rev() {
                let (node_rc, _) = &path[i];

                let (new_left_depth, new_right_depth, old_depth) = {
                    let n = node_rc.borrow();
                    (depth_of(&n.left_child_node), depth_of(&n.right_child_node), n.depth)
                };

                let max_depth = imax(new_left_depth, new_right_depth);

                if old_depth == max_depth {
                    break;
                }

                node_rc.borrow_mut().depth = max_depth;

                if (new_left_depth as i32) - (new_right_depth as i32) == 2 {
                    let left = node_rc.borrow().left_child_node.clone().unwrap();
                    let left_bal = { let l = left.borrow(); balance_of(&l) };
                    if left_bal > 0 {
                        rotate_left(self, &left);
                    }
                    rotate_right(self, node_rc);
                } else if (new_right_depth as i32) - (new_left_depth as i32) == 2 {
                    let right = node_rc.borrow().right_child_node.clone().unwrap();
                    let right_bal = { let r = right.borrow(); balance_of(&r) };
                    if right_bal < 0 {
                        rotate_right(self, &right);
                    }
                    rotate_left(self, node_rc);
                }
            }
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node_rc: &Rc<RefCell<BOSNode>>) {
        let has_left = node_rc.borrow().left_child_node.is_some();
        let has_right = node_rc.borrow().right_child_node.is_some();

        let mut bubble_up: Option<Rc<RefCell<BOSNode>>> = None;

        if has_left && has_right {
            // Case 1: Two children - find replacement candidate
            let go_left = {
                let n = node_rc.borrow();
                let ld = n.left_child_node.as_ref().map_or(0, |c| c.borrow().depth);
                let rd = n.right_child_node.as_ref().map_or(0, |c| c.borrow().depth);
                ld >= rd
            };

            if go_left {
                node_rc.borrow_mut().left_child_count -= 1;
            } else {
                node_rc.borrow_mut().right_child_count -= 1;
            }

            let mut candidate = if go_left {
                node_rc.borrow().left_child_node.clone().unwrap()
            } else {
                node_rc.borrow().right_child_node.clone().unwrap()
            };

            if go_left {
                while candidate.borrow().right_child_node.is_some() {
                    candidate.borrow_mut().right_child_count -= 1;
                    let next = candidate.borrow().right_child_node.clone().unwrap();
                    candidate = next;
                }
            } else {
                while candidate.borrow().left_child_node.is_some() {
                    candidate.borrow_mut().left_child_count -= 1;
                    let next = candidate.borrow().left_child_node.clone().unwrap();
                    candidate = next;
                }
            }

            let lost_child = if go_left {
                candidate.borrow().left_child_node.clone()
            } else {
                candidate.borrow().right_child_node.clone()
            };

            let bubble_start = candidate.borrow().parent_node.as_ref()
                .and_then(|w| w.upgrade()).unwrap();

            // Replace candidate with lost_child in bubble_start
            {
                let is_left = bubble_start.borrow().left_child_node.as_ref()
                    .map_or(false, |lc| Rc::ptr_eq(lc, &candidate));
                let mut bs = bubble_start.borrow_mut();
                if is_left {
                    bs.left_child_node = lost_child.clone();
                } else {
                    bs.right_child_node = lost_child.clone();
                }
            }

            if let Some(ref lc) = lost_child {
                lc.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
            }

            // Place candidate where node was
            let node_parent_weak = node_rc.borrow().parent_node.clone();
            let node_parent_rc = node_parent_weak.as_ref().and_then(|w| w.upgrade());

            match node_parent_rc {
                Some(ref np) => {
                    let is_left = np.borrow().left_child_node.as_ref()
                        .map_or(false, |lc| Rc::ptr_eq(lc, node_rc));
                    let mut parent = np.borrow_mut();
                    if is_left {
                        parent.left_child_node = Some(candidate.clone());
                    } else {
                        parent.right_child_node = Some(candidate.clone());
                    }
                }
                None => {
                    self.root_node = Some(candidate.clone());
                }
            }

            candidate.borrow_mut().parent_node = node_parent_weak;

            // Transfer node's children to candidate
            let (node_left, node_left_count, node_right, node_right_count) = {
                let n = node_rc.borrow();
                (n.left_child_node.clone(), n.left_child_count,
                 n.right_child_node.clone(), n.right_child_count)
            };

            {
                let mut c = candidate.borrow_mut();
                c.left_child_node = node_left.clone();
                c.left_child_count = node_left_count;
                c.right_child_node = node_right.clone();
                c.right_child_count = node_right_count;
            }

            if let Some(ref left) = node_left {
                left.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }
            if let Some(ref right) = node_right {
                right.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            // Rebalance from bubble_start up to candidate
            if !Rc::ptr_eq(&bubble_start, node_rc) {
                let mut bs = bubble_start.clone();
                while !Rc::ptr_eq(&bs, &candidate) {
                    {
                        let ld = depth_of(&bs.borrow().left_child_node);
                        let rd = depth_of(&bs.borrow().right_child_node);
                        bs.borrow_mut().depth = imax(ld, rd);
                    }

                    let bal = { let n = bs.borrow(); balance_of(&n) };
                    if bal > 1 {
                        let right = bs.borrow().right_child_node.clone().unwrap();
                        let right_bal = { let r = right.borrow(); balance_of(&r) };
                        if right_bal < 0 {
                            rotate_right(self, &right);
                        }
                        bs = rotate_left(self, &bs);
                    } else if bal < -1 {
                        let left = bs.borrow().left_child_node.clone().unwrap();
                        let left_bal = { let l = left.borrow(); balance_of(&l) };
                        if left_bal > 0 {
                            rotate_left(self, &left);
                        }
                        bs = rotate_right(self, &bs);
                    }

                    bs = bs.borrow().parent_node.as_ref()
                        .and_then(|w| w.upgrade()).unwrap();
                }
            }

            // Fix candidate's depth
            {
                let ld = depth_of(&candidate.borrow().left_child_node);
                let rd = depth_of(&candidate.borrow().right_child_node);
                candidate.borrow_mut().depth = imax(ld, rd);
            }

            bubble_up = candidate.borrow().parent_node.as_ref()
                .and_then(|w| w.upgrade());

            // Fix immediate parent's child count
            if let Some(ref bu) = bubble_up {
                let is_left = bu.borrow().left_child_node.as_ref()
                    .map_or(false, |lc| Rc::ptr_eq(lc, &candidate));
                if is_left {
                    bu.borrow_mut().left_child_count -= 1;
                } else {
                    bu.borrow_mut().right_child_count -= 1;
                }
            }
        } else {
            // Case 2: Zero or one child
            if node_rc.borrow().parent_node.is_none() {
                // Node is root
                let child = {
                    let n = node_rc.borrow();
                    if n.left_child_node.is_some() {
                        n.left_child_node.clone()
                    } else {
                        n.right_child_node.clone()
                    }
                };

                if let Some(ref c) = child {
                    c.borrow_mut().parent_node = None;
                }

                self.root_node = child;
                bubble_up = None;
            } else {
                let (child, child_count) = {
                    let n = node_rc.borrow();
                    if n.left_child_node.is_some() {
                        (n.left_child_node.clone(), n.left_child_count)
                    } else {
                        (n.right_child_node.clone(), n.right_child_count)
                    }
                };

                let parent = node_rc.borrow().parent_node.as_ref()
                    .and_then(|w| w.upgrade()).unwrap();

                let is_left = parent.borrow().left_child_node.as_ref()
                    .map_or(false, |lc| Rc::ptr_eq(lc, node_rc));

                {
                    let mut p = parent.borrow_mut();
                    if is_left {
                        p.left_child_node = child.clone();
                        p.left_child_count = child_count;
                    } else {
                        p.right_child_node = child.clone();
                        p.right_child_count = child_count;
                    }
                }

                if let Some(ref c) = child {
                    c.borrow_mut().parent_node = Some(Rc::downgrade(&parent));
                }

                bubble_up = Some(parent);
            }
        }

        // Common bubble-up phase: update depths, rebalance, decrement counts
        let mut bubbling_finished = false;
        while let Some(ref bu) = bubble_up {
            if !bubbling_finished {
                let (left_depth, right_depth, old_depth) = {
                    let n = bu.borrow();
                    (depth_of(&n.left_child_node), depth_of(&n.right_child_node), n.depth)
                };

                let new_depth = imax(left_depth, right_depth);
                let depth_changed = new_depth != old_depth;
                bu.borrow_mut().depth = new_depth;

                let bal = { let n = bu.borrow(); balance_of(&n) };
                if bal < -1 {
                    let left = bu.borrow().left_child_node.clone().unwrap();
                    let left_bal = { let l = left.borrow(); balance_of(&l) };
                    if left_bal > 0 {
                        rotate_left(self, &left);
                    }
                    bubble_up = Some(rotate_right(self, bu));
                } else if bal > 1 {
                    let right = bu.borrow().right_child_node.clone().unwrap();
                    let right_bal = { let r = right.borrow(); balance_of(&r) };
                    if right_bal < 0 {
                        rotate_right(self, &right);
                    }
                    bubble_up = Some(rotate_left(self, bu));
                } else {
                    if !depth_changed {
                        bubbling_finished = true;
                    }
                }
            }

            // Decrement parent's child count
            let parent_weak = bubble_up.as_ref().unwrap().borrow().parent_node.clone();
            if let Some(ref pw) = parent_weak {
                if let Some(parent) = pw.upgrade() {
                    let is_left = parent.borrow().left_child_node.as_ref()
                        .map_or(false, |lc| Rc::ptr_eq(lc, bubble_up.as_ref().unwrap()));
                    if is_left {
                        parent.borrow_mut().left_child_count -= 1;
                    } else {
                        parent.borrow_mut().right_child_count -= 1;
                    }
                }
            }

            bubble_up = parent_weak.and_then(|pw| pw.upgrade());
        }

        // Mark node as invalid and unref
        node_rc.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node_rc);

        // Clear removed node's pointers to release Rc references
        {
            let mut n = node_rc.borrow_mut();
            n.left_child_node = None;
            n.right_child_node = None;
            n.parent_node = None;
        }
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count -= 1;
        if node.borrow().weak_ref_count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            None
        } else if node.borrow().weak_ref_node_valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let cmp_fn = self.cmp_function;
        let mut current = self.root_node.clone();
        while let Some(ref node_rc) = current {
            let cmp = cmp_fn(key, &node_rc.borrow().key);
            if cmp == 0 {
                return Some(node_rc.clone());
            } else if cmp < 0 {
                let next = node_rc.borrow().left_child_node.clone();
                current = next;
            } else {
                let next = node_rc.borrow().right_child_node.clone();
                current = next;
            }
        }
        None
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();
        let mut idx = index;
        while let Some(ref node_rc) = current {
            let left_count = node_rc.borrow().left_child_count;
            if left_count <= idx {
                idx -= left_count;
                if idx == 0 {
                    return Some(node_rc.clone());
                }
                idx -= 1;
                let next = node_rc.borrow().right_child_node.clone();
                current = next;
            } else {
                let next = node_rc.borrow().left_child_node.clone();
                current = next;
            }
        }
        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        fn print_helper(node: &Rc<RefCell<BOSNode>>) {
            let (key, lcc, rcc, depth, parent_key, left, right) = {
                let n = node.borrow();
                let parent_key = n.parent_node.as_ref()
                    .and_then(|w| w.upgrade())
                    .map(|p| p.borrow().key.clone());
                (n.key.clone(), n.left_child_count, n.right_child_count, n.depth,
                 parent_key, n.left_child_node.clone(), n.right_child_node.clone())
            };

            println!("  \"{}\" [label=\"\\N ({},{},{})\"];", key, lcc, rcc, depth);
            if let Some(pk) = parent_key {
                println!("  \"{}\" -> \"{}\" [color=green];", key, pk);
            }
            if let Some(ref l) = left {
                println!("  \"{}\" -> \"{}\"", key, l.borrow().key);
                print_helper(l);
            }
            if let Some(ref r) = right {
                println!("  \"{}\" -> \"{}\"", key, r.borrow().key);
                print_helper(r);
            }
        }

        if let Some(ref root) = self.root_node {
            println!("digraph {{");
            println!("  ordering = out;");
            print_helper(root);
            println!("}}");
        }
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    assert!(node.borrow().weak_ref_count < 127);
    assert!(node.borrow().weak_ref_count > 0);
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(right) = node.borrow().right_child_node.clone() {
        let mut current = right;
        while let Some(left) = current.borrow().left_child_node.clone() {
            current = left;
        }
        return Some(current);
    }

    let mut current = node.clone();
    loop {
        let parent = current.borrow().parent_node.as_ref()
            .and_then(|w| w.upgrade());
        match parent {
            Some(p) => {
                let is_right = p.borrow().right_child_node.as_ref()
                    .map_or(false, |rc| Rc::ptr_eq(rc, &current));
                if is_right {
                    current = p;
                } else {
                    return Some(p);
                }
            }
            None => return None,
        }
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(left) = node.borrow().left_child_node.clone() {
        let mut current = left;
        while let Some(right) = current.borrow().right_child_node.clone() {
            current = right;
        }
        return Some(current);
    }

    let mut current = node.clone();
    loop {
        let parent = current.borrow().parent_node.as_ref()
            .and_then(|w| w.upgrade());
        match parent {
            Some(p) => {
                let is_left = p.borrow().left_child_node.as_ref()
                    .map_or(false, |lc| Rc::ptr_eq(lc, &current));
                if is_left {
                    current = p;
                } else {
                    return Some(p);
                }
            }
            None => return None,
        }
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current: Option<Rc<RefCell<BOSNode>>> = Some(node.clone());
    while let Some(ref curr) = current {
        let parent = curr.borrow().parent_node.as_ref()
            .and_then(|w| w.upgrade());
        if let Some(ref p) = parent {
            let is_right = p.borrow().right_child_node.as_ref()
                .map_or(false, |rc| Rc::ptr_eq(rc, curr));
            if is_right {
                counter += 1 + p.borrow().left_child_count;
            }
        }
        current = parent;
    }
    counter
}
